INSERT INTO `modx_usertest_tests` (`id`, `name`, `description`, `count_questions`, `count_questions_on_page`, `time_test`, `active`) VALUES (1, 'Можете ли вы', '<p>Если вы набрали от 30 до 39 баллов, это значит, что ребенок - самая большая ценность в вашей жизни. Вы стремитесь не только понять, но и узнать его, относитесь к нему с уважением, придерживаетесь наиболее прогрессивных принципов воспитания и постоянной линии поведения. Другими словами, вы действуете правильно и можете надеяться на хорошие результаты.</p><p>Сумма от 16 до 30 баллов: забота о ребенке для вас вопрос первостепенной важности. Вы обладаете способностями воспитателя, но на практике не всегда применяете их последовательно и целенаправленно. Порой вы чересчур строги, в других случаях - излишне мягки, кроме того, вы склонны к компромиссам, которые ослабляют воспитательный эффект. Вам следует серьезно задуматься над своим подходом к воспитанию ребенка.</p><p>Число баллов менее 16 говорит о том, что у вас серьезные проблемы с воспитанием ребенка. Вам недостает либо знаний, либо желания и стремления сделать ребенка личностью, а возможно, и того и другого.</p>', 0, 1, 0, 1);
